// [강의 배포용 / n8n Cloud] 시나리오 업로드 → 대상 사이트 검수 → Slack 리포트
// 수강생은 코드를 고치지 않는다. 폼에 (1) 대상 사이트 URL (2) 테스트시나리오.md 만 넣으면 된다.
//
// n8n Cloud는 로컬 파일/ localhost 에 접근할 수 없으므로:
//  - 시나리오: 폼으로 .md 업로드 (이 노드가 텍스트로 읽음)
//  - 대상:     폼에 입력한 공개 URL (예: https://내앱.vercel.app)
//
// 이 노드는 .md의 <!-- N8N-TEST-MATRIX --> 표를 파싱해 케이스를 만들고,
// 대상 사이트에 호출하여 상태코드+키워드로 Pass/Fail을 판정한다.

const item = $input.first();

// --- 1) 폼 입력에서 대상 URL 확보 (http(s) 로 시작하는 값 자동 인식) ---
const form = item.json || {};
let BASE = Object.values(form).find(v => typeof v === 'string' && /^https?:\/\//i.test(String(v).trim()));
if (!BASE) throw new Error('폼에 대상 사이트 URL(https:// 로 시작)을 입력하세요.');
BASE = String(BASE).trim().replace(/\/+$/, '');

// --- 2) 업로드된 .md 텍스트 확보 (바이너리 키 자동 탐지) ---
let md = '';
const binKeys = Object.keys(item.binary || {});
if (binKeys.length && this.helpers && this.helpers.getBinaryDataBuffer) {
  const buf = await this.helpers.getBinaryDataBuffer(0, binKeys[0]);
  md = buf.toString('utf8');
} else {
  md = form.data || form.text || Object.values(form).find(v => typeof v === 'string' && v.length > 80) || '';
}
if (!md) throw new Error('업로드된 .md 텍스트를 읽지 못했습니다. 폼에서 .md 파일을 첨부했는지 확인하세요.');

// --- 3) N8N-TEST-MATRIX 구간 추출 + 표 파싱 ---
const block = md.match(/N8N-TEST-MATRIX:START([\s\S]*?)N8N-TEST-MATRIX:END/);
if (!block) throw new Error('업로드한 .md에서 N8N-TEST-MATRIX 구간을 찾지 못했습니다.');

const cells = (line) => line.split('|').slice(1, -1).map(s => s.trim());
const isSep = (arr) => arr.every(x => /^:?-+:?$/.test(x));
const rows = block[1].split('\n').map(l => l.trim()).filter(l => l.startsWith('|'));
const header = cells(rows[0]);
const idx = (n) => header.indexOf(n);

const CASES = [];
for (let i = 1; i < rows.length; i++) {
  const c = cells(rows[i]);
  if (isSep(c)) continue;
  const get = (n) => { const k = idx(n); return k >= 0 ? (c[k] || '') : ''; };
  const bodyRaw = get('body');
  let body;
  if (bodyRaw && bodyRaw !== '-') { try { body = JSON.parse(bodyRaw); } catch (e) { body = undefined; } }
  const kw = get('keyword');
  CASES.push({
    tc: get('TC'), name: get('name'),
    method: (get('method') || 'GET').toUpperCase(),
    path: get('path'), body,
    expectStatus: parseInt(get('expectStatus'), 10) || 200,
    keyword: (kw && kw !== '-') ? kw : '',
  });
}
if (CASES.length === 0) throw new Error('매트릭스에서 실행할 케이스를 파싱하지 못했습니다.');

// --- 4) 케이스별 호출 + 판정 ---
const __HTTP = (this && this.helpers && this.helpers.httpRequest)
  ? this.helpers.httpRequest.bind(this.helpers)
  : (typeof $helpers !== 'undefined' && $helpers.httpRequest ? $helpers.httpRequest.bind($helpers) : null);
if (!__HTTP) throw new Error('n8n httpRequest 헬퍼를 찾을 수 없습니다.');

const results = [];
for (const c of CASES) {
  let status = 0, bodyText = '', errMsg = '';
  try {
    const opt = {
      method: c.method,
      url: encodeURI(BASE + c.path),
      returnFullResponse: true,
      json: true,
      timeout: 15000,
      headers: { 'Content-Type': 'application/json' },
    };
    if (c.body !== undefined) opt.body = c.body;
    const res = await __HTTP(opt);
    status = res.statusCode || 200;
    bodyText = typeof res.body === 'string' ? res.body : JSON.stringify(res.body || {});
  } catch (err) {
    const __resp = err.response || (err.cause && err.cause.response) || {};
    const __m = String(err.message || '').match(/status code (\d{3})/);
    status = __resp.status || __resp.statusCode || err.statusCode || err.httpCode || (__m ? Number(__m[1]) : 0);
    const eb = __resp.data ?? __resp.body ?? (err.cause && err.cause.response && err.cause.response.data) ?? (err.context && err.context.data) ?? '';
    bodyText = typeof eb === 'string' ? eb : JSON.stringify(eb || {});
    errMsg = err.message || '';
  }
  const statusOk = status === c.expectStatus;
  // n8n httpRequest는 4xx/5xx 응답 본문을 넘기지 않는다.
  // → 본문이 있으면(주로 2xx) 키워드까지 검증, 본문이 없으면(에러 응답) 상태코드로 판정
  const bodyAvailable = bodyText.length > 0;
  const keywordChecked = !!c.keyword && bodyAvailable;
  const keywordOk = !c.keyword || (bodyAvailable ? bodyText.includes(c.keyword) : statusOk);
  const pass = statusOk && keywordOk;
  let reason = 'OK';
  if (!pass) {
    if (status === 0) reason = '연결 실패 — 대상 URL/네트워크 확인 (' + BASE + ')';
    else if (!statusOk) reason = '상태 ' + status + ' (기대 ' + c.expectStatus + ')';
    else reason = "키워드 '" + c.keyword + "' 미검출";
    if (errMsg) reason += ' / ' + errMsg;
  }
  results.push({ tc: c.tc, name: c.name, request: c.method + ' ' + c.path, expectStatus: c.expectStatus, actualStatus: status, pass, reason });
}

const total = results.length;
const passed = results.filter(r => r.pass).length;
const failed = total - passed;
const passRate = Math.round((passed / total) * 1000) / 10;
const verdict = failed === 0 ? 'PASS' : 'FAIL';
const ranAt = new Date().toISOString();

// --- 5) 케이스별 개별 Slack 메시지 (+ 마지막 요약 1건) ---
// Code가 여러 아이템을 반환하면 다음 Slack 노드가 아이템당 1번씩 실행된다 → 케이스별 개별 메시지
const out = [];

for (const r of results) {
  const icon = r.pass ? ':white_check_mark:' : ':x:';
  const head = icon + ' *' + r.tc + '* ' + r.name + '  —  ' + (r.pass ? 'PASS' : 'FAIL');
  const detail = '`' + r.request + '`  ·  기대 ' + r.expectStatus + ' / 실제 ' + r.actualStatus + (r.pass ? '' : '\n> ' + r.reason);
  out.push({ json: {
    kind: 'case', tc: r.tc, pass: r.pass, baseUrl: BASE,
    slackPayload: {
      text: '[' + (r.pass ? 'PASS' : 'FAIL') + '] ' + r.tc + ' ' + r.name,
      blocks: [
        { type: 'section', text: { type: 'mrkdwn', text: head + '\n' + detail } },
        { type: 'context', elements: [{ type: 'mrkdwn', text: '대상 ' + BASE + ' · ' + ranAt }] },
      ],
    },
  } });
}

// 마지막 요약 메시지 (필요 없으면 이 블록 삭제)
out.push({ json: {
  kind: 'summary', verdict, total, passed, failed, passRate, baseUrl: BASE, ranAt,
  slackPayload: {
    text: '검수 요약 ' + verdict + ' — ' + passed + '/' + total + ' pass',
    blocks: [
      { type: 'header', text: { type: 'plain_text', text: '검수 요약 ' + verdict, emoji: true } },
      { type: 'section', fields: [
        { type: 'mrkdwn', text: '*결과*\n' + (verdict === 'PASS' ? ':white_check_mark: PASS' : ':rotating_light: FAIL') },
        { type: 'mrkdwn', text: '*Pass / Fail*\n' + passed + ' / ' + failed + '  (' + passRate + '%)' },
        { type: 'mrkdwn', text: '*대상*\n' + BASE },
        { type: 'mrkdwn', text: '*케이스 수*\n' + total + '건' },
      ] },
    ],
  },
} });

return out;
